#include <iostream>
using namespace std;

int main() {
    int n;
    cout << "Enter a positive integer: ";
    cin >> n;

    for (int i = 1; i <= n; i++) {
        if (i % 2 == 0) {
            cout << i << " is even" << endl;
        } else {
            cout << i << " is odd" << endl;
        }
    }

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int num;
    bool isPrime = true;

    cout << "Enter a positive integer: ";
    cin >> num;

    if (num <= 1) {
        isPrime = false;
    } else {
        int i = 2;
        while (i * i <= num) {
            if (num % i == 0) {
                isPrime = false;
                break;  // Early exit when divisor found
            }
            i++;
        }
    }

    if (isPrime) {
        cout << num << " is a prime number" << endl;
    } else {
        cout << num << " is not a prime number" << endl;
    }

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    double balance = 1000.00;
    int choice;

    cout << "=== Welcome to ATM ===" << endl;

    while (true) {
        cout << "\n--- Main Menu ---";
        cout << "\n1. Check Balance";
        cout << "\n2. Deposit Money";
        cout << "\n3. Withdraw Money";
        cout << "\n4. Exit";
        cout << "\nEnter your choice: ";
        cin >> choice;

        switch (choice) {
            case 1:
                cout << "Your current balance is: $" << balance << endl;
                break;

            case 2: {
                double deposit;
                cout << "Enter amount to deposit: $";
                cin >> deposit;

                if (deposit > 0) {
                    balance += deposit;
                    cout << "Deposit successful! New balance: $" << balance << endl;
                } else {
                    cout << "Invalid amount! Deposit must be positive." << endl;
                }
                break;
            }

            case 3: {
                double withdraw;
                cout << "Enter amount to withdraw: $";
                cin >> withdraw;

                if (withdraw > 0 && withdraw <= balance) {
                    balance -= withdraw;
                    cout << "Withdrawal successful! New balance: $" << balance << endl;
                } else if (withdraw > balance) {
                    cout << "Insufficient balance!" << endl;
                } else {
                    cout << "Invalid amount!" << endl;
                }
                break;
            }

            case 4:
                cout << "Thank you for using ATM. Goodbye!" << endl;
                return 0;

            default:
                cout << "Invalid choice! Please try again." << endl;
                continue;  // Skip to next iteration for invalid input
        }
    }

    return 0;
}
